import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Avatar, icon } from 'decantr/components';

code.example:
function ProfileSettings({ user, onSave }) {
  const { div, form, h2, input, label, textarea } = tags;
  const [name, setName] = createSignal(user.name);
  const [email, setEmail] = createSignal(user.email);
  const [bio, setBio] = createSignal(user.bio || '');
  const [avatar, setAvatar] = createSignal(user.avatar);

  const handleAvatarChange = (e) => {
    const file = e.target.files[0];
    if (file) setAvatar(URL.createObjectURL(file));
  };

  return div({ class: css('_flex _col _gap8 _maxw[600px]') },
    h2({ class: css('_heading4 _mb4') }, 'Profile'),
    div({ class: css('_flex _aic _gap6') },
      div({ class: css('_relative') },
        Avatar({ src: avatar(), size: 'xl' }),
        label({ class: css('_absolute _bottom0 _right0 _w8 _h8 _rfull _bgPrimary _flex _center _cursor[pointer]') },
          icon('camera', { size: '14', class: css('_fgWhite') }),
          input({ type: 'file', accept: 'image/*', class: css('_hidden'), onchange: handleAvatarChange })
        )
      ),
      div({ class: css('_flex _col _gap1') },
        Button({ variant: 'outline', size: 'sm' }, 'Change photo'),
        Button({ variant: 'ghost', size: 'sm', class: css('_fgmuted') }, 'Remove')
      )
    ),
    form({ class: css('_flex _col _gap4'), onsubmit: (e) => { e.preventDefault(); onSave({ name: name(), email: email(), bio: bio(), avatar: avatar() }); } },
      div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'Name'),
        input({ type: 'text', class: css('carbon-input _p2 _r2'), value: name(), oninput: (e) => setName(e.target.value) })
      ),
      div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'Email'),
        input({ type: 'email', class: css('carbon-input _p2 _r2'), value: email(), oninput: (e) => setEmail(e.target.value) })
      ),
      div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'Bio'),
        textarea({ class: css('carbon-input _p2 _r2 _resize[vertical]'), rows: 3, value: bio(), oninput: (e) => setBio(e.target.value), placeholder: 'Tell us about yourself...' })
      ),
      Button({ type: 'submit', variant: 'primary' }, 'Save Changes')
    )
  );
}

