function SecuritySettings({ user, onChangePassword, onToggleMFA }) {
  const { div, form, h2, h3, p, input, label } = tags;
  const [currentPw, setCurrentPw] = createSignal('');
  const [newPw, setNewPw] = createSignal('');
  const [confirmPw, setConfirmPw] = createSignal('');

  return div({ class: css('_flex _col _gap8 _maxw[600px]') },
    h2({ class: css('_heading4 _mb4') }, 'Security'),
    div({ class: css('carbon-card _p6 _r2') },
      h3({ class: css('_heading5 _mb4') }, 'Change password'),
      form({ class: css('_flex _col _gap4'), onsubmit: (e) => { e.preventDefault(); onChangePassword({ current: currentPw(), new: newPw() }); } },
        div({ class: css('_flex _col _gap1') },
          label({ class: css('_textsm _font500') }, 'Current password'),
          input({ type: 'password', class: css('carbon-input _p2 _r2'), value: currentPw(), oninput: (e) => setCurrentPw(e.target.value) })
        ),
        div({ class: css('_flex _col _gap1') },
          label({ class: css('_textsm _font500') }, 'New password'),
          input({ type: 'password', class: css('carbon-input _p2 _r2'), value: newPw(), oninput: (e) => setNewPw(e.target.value) })
        ),
        div({ class: css('_flex _col _gap1') },
          label({ class: css('_textsm _font500') }, 'Confirm new password'),
          input({ type: 'password', class: css('carbon-input _p2 _r2'), value: confirmPw(), oninput: (e) => setConfirmPw(e.target.value) })
        ),
        Button({ type: 'submit', variant: 'primary' }, 'Update Password')
      )
    ),
    div({ class: css('carbon-card _p6 _r2 _flex _jcsb _aic') },
      div({},
        div({ class: css('_flex _aic _gap2 _mb1') },
          h3({ class: css('_heading5') }, 'Two-factor authentication'),
          user.mfaEnabled ? Badge({ variant: 'success', size: 'sm' }, 'Enabled') : Badge({ variant: 'outline', size: 'sm' }, 'Disabled')
        ),
        p({ class: css('_textsm _fgmuted') }, 'Add an extra layer of security to your account')
      ),
      Button({ variant: user.mfaEnabled ? 'outline' : 'primary', onclick: onToggleMFA },
        user.mfaEnabled ? 'Disable' : 'Enable'
      )
    )
  );
}

