function PreferencesSettings({ preferences, onSave }) {
  const { div, h2, h3, p, label, select, option } = tags;
  const [theme, setTheme] = createSignal(preferences.theme);
  const [emailNotifs, setEmailNotifs] = createSignal(preferences.emailNotifications);
  const [language, setLanguage] = createSignal(preferences.language);

  const themes = ['light', 'dark', 'auto'];
  const languages = [{ code: 'en', name: 'English' }, { code: 'es', name: 'Spanish' }, { code: 'fr', name: 'French' }];

  return div({ class: css('_flex _col _gap8 _maxw[600px]') },
    h2({ class: css('_heading4 _mb4') }, 'Preferences'),
    div({ class: css('carbon-card _p6 _r2') },
      h3({ class: css('_heading5 _mb4') }, 'Appearance'),
      div({ class: css('_flex _gap3') },
        ...themes.map(t =>
          Button({
            variant: theme() === t ? 'primary' : 'outline',
            onclick: () => setTheme(t)
          }, icon(t === 'dark' ? 'moon' : t === 'light' ? 'sun' : 'monitor'), t.charAt(0).toUpperCase() + t.slice(1))
        )
      )
    ),
    div({ class: css('carbon-card _p6 _r2') },
      h3({ class: css('_heading5 _mb4') }, 'Notifications'),
      label({ class: css('_flex _aic _jcsb _cursor[pointer]') },
        div({},
          p({ class: css('_font500') }, 'Email notifications'),
          p({ class: css('_textsm _fgmuted') }, 'Receive updates about your account')
        ),
        input({ type: 'checkbox', checked: emailNotifs(), onchange: () => setEmailNotifs(!emailNotifs()), class: css('_w5 _h5') })
      )
    ),
    div({ class: css('carbon-card _p6 _r2') },
      h3({ class: css('_heading5 _mb4') }, 'Language'),
      select({ class: css('carbon-input _p2 _r2 _wfull'), value: language(), onchange: (e) => setLanguage(e.target.value) },
        ...languages.map(l => option({ value: l.code }, l.name))
      )
    ),
    Button({ variant: 'primary', onclick: () => onSave({ theme: theme(), emailNotifications: emailNotifs(), language: language() }) }, 'Save Preferences')
  );
}

