function DangerZoneSettings({ user, onDelete }) {
  const { div, h2, h3, p, input, label } = tags;
  const [confirm, setConfirm] = createSignal('');
  const confirmText = 'delete my account';

  return div({ class: css('_flex _col _gap6 _maxw[600px]') },
    h2({ class: css('_heading4 _fgDanger _mb4') }, 'Danger Zone'),
    div({ class: css('_p6 _r2 _border[2px] _borderDanger/50') },
      div({ class: css('_flex _aic _gap3 _mb4') },
        icon('alert-triangle', { class: css('_fgDanger') }),
        h3({ class: css('_heading5 _fgDanger') }, 'Delete Account')
      ),
      p({ class: css('_fgmuted _mb4') }, 'Once you delete your account, there is no going back. All your data will be permanently removed.'),
      div({ class: css('_flex _col _gap2 _mb4') },
        label({ class: css('_textsm _font500') }, `Type "${confirmText}" to confirm:`),
        input({ type: 'text', class: css('carbon-input _p2 _r2'), value: confirm(), oninput: (e) => setConfirm(e.target.value), placeholder: confirmText })
      ),
      Button({
        variant: 'primary',
        class: css('_bgDanger _wfull'),
        disabled: confirm() !== confirmText,
        onclick: onDelete
      }, icon('trash'), 'Delete Account')
    )
  );
}

